function report = runSpin2ImageTest(testNumber, options)
%RUNSPIN2IMAGETEST Run one enumerated real-image spin-2 experiment.
%
% From the repository root:
%   matlab -batch "addpath('examples'); runSpin2ImageTest(1);"
%
% Tests:
%   1 - R and G from the first TIFF.
%   2 - R and projectively warped G from the first TIFF.
%   3 - R from each TIFF after a common center crop (unrelated scenes).
%
% MaximumDimension controls the overview level only. The final result is
% always evaluated on the full cropped image.

arguments
    testNumber (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeMember(testNumber, 1:3)}
    options.MaximumDimension (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 1024
    options.SearchRadius (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = [8, 8]
    options.ResidualSearchRadius (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = [4, 4]
    options.PyramidDecimation (1, 1) double ...
        {mustBeFinite, mustBeInteger, ...
        mustBeGreaterThanOrEqual(options.PyramidDecimation, 2)} = 2
    options.UseIntermediateLevels (1, 1) logical = false
    options.PatchRadius (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 5
    options.Stride (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 12
    options.TileSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [512, 512]
    options.TileOverlap (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = [0, 0]
    options.ConstrainMatchesToTile (1, 1) logical = false
    options.NumWorkers (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.TuneThreads (1, 1) logical = false
    options.ExhaustiveThreadTuning (1, 1) logical = false
    options.ThreadTuningRepetitions (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 2
    options.SmoothingSigma (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 0.8
    options.GradientThreshold (1, 1) double ...
        {mustBeFinite, mustBePositive} = 4
    options.Display (1, 1) logical = true
end

projectRoot = fileparts(fileparts(mfilename("fullpath")));
sourceFolder = fullfile(projectRoot, "src");
testDataFolder = fullfile(projectRoot, "test_data");
addpath(sourceFolder);
pathCleanup = onCleanup(@() rmpath(sourceFolder));

testFiles = dir(fullfile(testDataFolder, "*.tif"));
[~, order] = sort(lower(string({testFiles.name})));
testFiles = testFiles(order);
if numel(testFiles) < 2
    error("runSpin2ImageTest:MissingData", ...
        "Expected at least two TIFF images in %s.", testDataFolder);
end

totalTimer = tic;
readTimer = tic;
firstRgb = imread(fullfile(testFiles(1).folder, testFiles(1).name));
image1 = firstRgb(:, :, 1);
if testNumber < 3
    image2 = firstRgb(:, :, 2);
    secondFileName = testFiles(1).name;
else
    secondRgb = imread(fullfile(testFiles(2).folder, testFiles(2).name));
    image2 = secondRgb(:, :, 1);
    secondFileName = testFiles(2).name;
end

[image1, image2] = centerCropToCommonSize(image1, image2);
sourceBeforeWarp = image2;
readSeconds = toc(readTimer);

warpSeconds = 0;
projectiveMatrix = eye(3);
if testNumber == 2
    warpTimer = tic;
    projectiveMatrix = modestProjectiveMatrix(size(image2));
    image2 = warpProjective(image2, projectiveMatrix);
    warpSeconds = toc(warpTimer);
end

matcher = Spin2Matcher(image1, image2);
[dx, dy] = meshgrid( ...
    -options.SearchRadius(1):options.SearchRadius(1), ...
    -options.SearchRadius(2):options.SearchRadius(2));
searchOffsets = [dx(:), dy(:)];

features = struct();
diagnosticPrepareSeconds = 0;
threadTuning = [];
numberOfWorkers = options.NumWorkers;
if options.Display || options.TuneThreads
    diagnosticPrepareTimer = tic;
    features = matcher.prepareComplexGradients( ...
        SmoothingSigma=options.SmoothingSigma, ...
        GradientThreshold=options.GradientThreshold);
    diagnosticPrepareSeconds = toc(diagnosticPrepareTimer);
end
if options.TuneThreads
    [tuningDx, tuningDy] = meshgrid( ...
        -options.ResidualSearchRadius(1):options.ResidualSearchRadius(1), ...
        -options.ResidualSearchRadius(2):options.ResidualSearchRadius(2));
    threadTuning = matcher.tuneThreads( ...
        [tuningDx(:), tuningDy(:)], ...
        Exhaustive=options.ExhaustiveThreadTuning, ...
        Repetitions=options.ThreadTuningRepetitions, ...
        PatchRadius=options.PatchRadius, Stride=options.Stride, ...
        TileSize=options.TileSize, TileOverlap=options.TileOverlap, ...
        ConstrainMatchesToTile=options.ConstrainMatchesToTile);
    numberOfWorkers = threadTuning.RecommendedWorkers;
end

pyramidTimer = tic;
result = matcher.matchPyramid(searchOffsets, ...
    OverviewMaximumDimension=options.MaximumDimension, ...
    PyramidDecimation=options.PyramidDecimation, ...
    UseIntermediateLevels=options.UseIntermediateLevels, ...
    ResidualSearchRadius=options.ResidualSearchRadius, ...
    PatchRadius=options.PatchRadius, ...
    Stride=options.Stride, ...
    TileSize=options.TileSize, ...
    TileOverlap=options.TileOverlap, ...
    ConstrainMatchesToTile=options.ConstrainMatchesToTile, ...
    SmoothingSigma=options.SmoothingSigma, ...
    GradientThreshold=options.GradientThreshold, ...
    NumWorkers=numberOfWorkers);
pyramidSeconds = toc(pyramidTimer);
prepareSeconds = sum([result.LevelReports.PrepareSeconds]);
matchSeconds = sum([result.LevelReports.MatchSeconds]);

[expectedDx, expectedDy] = expectedDisplacement( ...
    result, projectiveMatrix, testNumber < 3);
[residualX, residualY, truthValid] = calculateResiduals( ...
    result, expectedDx, expectedDy, size(image1));
summary = summarizeResult(result, residualX, residualY, truthValid);

displaySeconds = 0;
figureHandle = [];
if options.Display
    displayTimer = tic;
    figureHandle = showDiagnostics(testNumber, image1, ...
        sourceBeforeWarp, image2, features, result, ...
        expectedDx, expectedDy, residualX, residualY, summary);
    displaySeconds = toc(displayTimer);
end
totalSeconds = toc(totalTimer);

timing = struct( ...
    "ReadAndCropSeconds", readSeconds, ...
    "WarpSeconds", warpSeconds, ...
    "DiagnosticPrepareSeconds", diagnosticPrepareSeconds, ...
    "PrepareSeconds", prepareSeconds, ...
    "MatchSeconds", matchSeconds, ...
    "PyramidSeconds", pyramidSeconds, ...
    "DisplaySeconds", displaySeconds, ...
    "TotalSeconds", totalSeconds);
report = struct( ...
    "TestNumber", testNumber, ...
    "Description", testDescription(testNumber), ...
    "FirstFile", string(testFiles(1).name), ...
    "SecondFile", string(secondFileName), ...
    "WorkingImageSize", size(image1), ...
    "PyramidFactors", result.PyramidFactors, ...
    "LevelReports", result.LevelReports, ...
    "ThreadTuning", threadTuning, ...
    "NumWorkers", result.LevelReports(1).NumWorkers, ...
    "ProjectiveMatrix", projectiveMatrix, ...
    "Timing", timing, ...
    "Summary", summary, ...
    "ExpectedDisplacementX", expectedDx, ...
    "ExpectedDisplacementY", expectedDy, ...
    "ResidualX", residualX, ...
    "ResidualY", residualY, ...
    "Result", result, ...
    "Figure", figureHandle);

printReport(report, size(searchOffsets, 1));
if testNumber == 3
    fprintf("Test 3 has no true correspondence. Valid means that a patch " + ...
        "had sufficient gradient support; it does not mean that the " + ...
        "selected match is correct.\n");
end

clear pathCleanup
end

function description = testDescription(testNumber)
descriptions = [ ...
    "First TIFF: red channel versus green channel", ...
    "First TIFF: red channel versus projectively warped green channel", ...
    "Unrelated TIFFs: red channel versus red channel"];
description = descriptions(testNumber);
end

function [first, second] = centerCropToCommonSize(first, second)
commonHeight = min(size(first, 1), size(second, 1));
commonWidth = min(size(first, 2), size(second, 2));
firstRow = floor((size(first, 1) - commonHeight) / 2) + 1;
firstColumn = floor((size(first, 2) - commonWidth) / 2) + 1;
secondRow = floor((size(second, 1) - commonHeight) / 2) + 1;
secondColumn = floor((size(second, 2) - commonWidth) / 2) + 1;
first = first(firstRow:firstRow+commonHeight-1, ...
    firstColumn:firstColumn+commonWidth-1);
second = second(secondRow:secondRow+commonHeight-1, ...
    secondColumn:secondColumn+commonWidth-1);
end

function matrix = modestProjectiveMatrix(imageSize)
imageHeight = imageSize(1);
imageWidth = imageSize(2);
centerX = (imageWidth + 1) / 2;
centerY = (imageHeight + 1) / 2;
angleRadians = deg2rad(0.35);
centeredTransform = [ ...
    cos(angleRadians), -sin(angleRadians), 4; ...
    sin(angleRadians),  cos(angleRadians), -3; ...
    0.012/imageWidth, -0.008/imageHeight, 1];
toCenter = [1, 0, -centerX; 0, 1, -centerY; 0, 0, 1];
fromCenter = [1, 0, centerX; 0, 1, centerY; 0, 0, 1];
matrix = fromCenter * centeredTransform * toCenter;
end

function warped = warpProjective(image, matrix)
[imageHeight, imageWidth] = size(image);
[outputX, outputY] = meshgrid(1:imageWidth, 1:imageHeight);
inputHomogeneous = matrix \ [outputX(:).'; outputY(:).'; ...
    ones(1, numel(outputX))];
inputX = inputHomogeneous(1, :) ./ inputHomogeneous(3, :);
inputY = inputHomogeneous(2, :) ./ inputHomogeneous(3, :);
warpedValues = interp2(single(image), inputX, inputY, "linear", 0);
warped = uint8(round(reshape(warpedValues, imageHeight, imageWidth)));
end

function [expectedDx, expectedDy] = expectedDisplacement( ...
        result, matrix, hasCorrespondence)
[referenceX, referenceY] = meshgrid( ...
    result.ReferenceX, result.ReferenceY);
if hasCorrespondence
    sourceHomogeneous = matrix * [referenceX(:).'; referenceY(:).'; ...
        ones(1, numel(referenceX))];
    sourceX = reshape(sourceHomogeneous(1, :) ...
        ./ sourceHomogeneous(3, :), size(referenceX));
    sourceY = reshape(sourceHomogeneous(2, :) ...
        ./ sourceHomogeneous(3, :), size(referenceY));
    expectedDx = sourceX - referenceX;
    expectedDy = sourceY - referenceY;
else
    expectedDx = nan(size(referenceX));
    expectedDy = nan(size(referenceY));
end
end

function [residualX, residualY, truthValid] = calculateResiduals( ...
        result, expectedDx, expectedDy, imageSize)
expectedSourceX = result.ReferenceX + expectedDx;
expectedSourceY = result.ReferenceY + expectedDy;
truthValid = result.Valid & isfinite(expectedDx) & isfinite(expectedDy) ...
    & expectedSourceX >= 1 & expectedSourceX <= imageSize(2) ...
    & expectedSourceY >= 1 & expectedSourceY <= imageSize(1);
residualX = double(result.DisplacementX) - expectedDx;
residualY = double(result.DisplacementY) - expectedDy;
residualX(~truthValid) = NaN;
residualY(~truthValid) = NaN;
end

function summary = summarizeResult(result, residualX, residualY, truthValid)
valid = result.Valid;
costValues = result.Cost(valid);
marginValues = result.Margin(valid & isfinite(result.Margin));
dxValues = result.DisplacementX(valid);
dyValues = result.DisplacementY(valid);
residualXValues = residualX(truthValid);
residualYValues = residualY(truthValid);
endpointError = hypot(residualX, residualY);

summary = struct( ...
    "ValidFraction", nnz(valid) / numel(valid), ...
    "MedianCost", safeMedian(costValues), ...
    "MedianMargin", safeMedian(marginValues), ...
    "MedianDisplacementX", safeMedian(dxValues), ...
    "MedianDisplacementY", safeMedian(dyValues), ...
    "TruthSampleCount", nnz(truthValid), ...
    "MedianResidualX", safeMedian(residualXValues), ...
    "MedianResidualY", safeMedian(residualYValues), ...
    "MedianAbsoluteResidualX", safeMedian(abs(residualXValues)), ...
    "MedianAbsoluteResidualY", safeMedian(abs(residualYValues)), ...
    "RmseResidualX", safeRootMeanSquare(residualXValues), ...
    "RmseResidualY", safeRootMeanSquare(residualYValues), ...
    "MedianEndpointError", safeMedian(endpointError(truthValid)));
end

function value = safeMedian(values)
if isempty(values)
    value = NaN;
else
    value = median(double(values), "omitnan");
end
end

function value = safeRootMeanSquare(values)
if isempty(values)
    value = NaN;
else
    value = sqrt(mean(double(values) .^ 2, "omitnan"));
end
end

function figureHandle = showDiagnostics(testNumber, referenceImage, ...
        sourceBeforeWarp, sourceImage, features, result, ...
        expectedDx, expectedDy, residualX, residualY, summary)
figureName = sprintf("Spin-2 real-image test %d", testNumber);
figureHandle = uifigure(Name=figureName, Position=[40, 20, 1500, 1000]);
layout = uigridlayout(figureHandle, [4, 4]);
layout.RowHeight = {"1x", "1x", "1x", "1x"};
layout.ColumnWidth = {"1x", "1x", "1x", "1x"};
layout.Padding = [4, 4, 4, 4];
layout.RowSpacing = 4;
layout.ColumnSpacing = 4;

phaseReference = mod(angle(features.Reference) + pi, 2*pi) / (2*pi);
phaseSource = mod(angle(features.Source) + pi, 2*pi) / (2*pi);
addImagePanel(layout, 1, 1, referenceImage, "Reference channel");
addImagePanel(layout, 1, 2, sourceBeforeWarp, "Source before warp");
addImagePanel(layout, 1, 3, sourceImage, "Matcher source");
addImagePanel(layout, 1, 4, uint8(255 .* result.Valid), ...
    sprintf("Valid support: %.1f%%", 100 * summary.ValidFraction));

addImagePanel(layout, 2, 1, mapToRgb(phaseReference, hsv(256), ...
    features.ReferenceConfidence > 0), "Reference spin-2 phase");
addImagePanel(layout, 2, 2, mapToRgb(phaseSource, hsv(256), ...
    features.SourceConfidence > 0), "Source spin-2 phase");
addImagePanel(layout, 2, 3, mapToRgb( ...
    features.ReferenceConfidence, gray(256), true(size(referenceImage))), ...
    "Reference confidence");
addImagePanel(layout, 2, 4, mapToRgb( ...
    features.SourceConfidence, gray(256), true(size(sourceImage))), ...
    "Source confidence");

addImagePanel(layout, 3, 1, mapSignedToRgb( ...
    result.DisplacementX, result.Valid), "Displacement X (pixels)");
addImagePanel(layout, 3, 2, mapSignedToRgb( ...
    result.DisplacementY, result.Valid), "Displacement Y (pixels)");
addImagePanel(layout, 3, 3, mapToRgb( ...
    result.Cost, turbo(256), result.Valid), ...
    sprintf("Cost, median %.3f", summary.MedianCost));
addImagePanel(layout, 3, 4, mapToRgb( ...
    result.Margin, turbo(256), result.Valid), ...
    sprintf("Margin, median %.3f", summary.MedianMargin));

addImagePanel(layout, 4, 1, mapSignedToRgb( ...
    expectedDx, isfinite(expectedDx)), "Expected displacement X");
addImagePanel(layout, 4, 2, mapSignedToRgb( ...
    expectedDy, isfinite(expectedDy)), "Expected displacement Y");
addImagePanel(layout, 4, 3, mapSignedToRgb( ...
    residualX, isfinite(residualX)), ...
    sprintf("Residual X, RMSE %.3f", summary.RmseResidualX));
addImagePanel(layout, 4, 4, mapSignedToRgb( ...
    residualY, isfinite(residualY)), ...
    sprintf("Residual Y, RMSE %.3f", summary.RmseResidualY));
end

function addImagePanel(layout, row, column, image, panelTitle)
viewer = viewer2d(layout);
viewer.Layout.Row = row;
viewer.Layout.Column = column;
title(viewer, panelTitle);
imageshow(image, Parent=viewer, PyramidSmoothing="nearest");
end

function rgb = mapSignedToRgb(values, valid)
finiteValues = double(values(valid & isfinite(values)));
limit = max(abs(finiteValues), [], "all");
if isempty(limit) || limit == 0
    limit = 1;
end
normalized = (double(values) + limit) / (2 * limit);
rgb = mapToRgb(normalized, turbo(256), valid);
end

function rgb = mapToRgb(values, colorMap, valid)
valid = valid & isfinite(values);
finiteValues = double(values(valid));
if isempty(finiteValues)
    lowerLimit = 0;
    upperLimit = 1;
else
    lowerLimit = min(finiteValues, [], "all");
    upperLimit = max(finiteValues, [], "all");
end
if upperLimit <= lowerLimit
    upperLimit = lowerLimit + 1;
end
normalized = (double(values) - lowerLimit) / (upperLimit - lowerLimit);
normalized = max(0, min(1, normalized));
normalized(~valid) = 0;
indices = 1 + round((size(colorMap, 1) - 1) .* normalized);
rgb = reshape(uint8(round(255 .* colorMap(indices(:), :))), ...
    [size(values, 1), size(values, 2), 3]);
invalidRgb = repmat(~valid, 1, 1, 3);
rgb(invalidRgb) = 0;
end

function printReport(report, candidateCount)
fprintf("\nSpin-2 image test %d: %s\n", ...
    report.TestNumber, report.Description);
fprintf("  Files: %s | %s\n", report.FirstFile, report.SecondFile);
fprintf("  Full working image: %d x %d; pyramid factors [%s]\n", ...
    report.WorkingImageSize(1), report.WorkingImageSize(2), ...
    strjoin(string(report.PyramidFactors), " "));
fprintf("  Overview candidates: %d; thread workers: %d\n", ...
    candidateCount, report.NumWorkers);
fprintf("  Timing (s): read/crop %.3f, warp %.3f, " + ...
    "pyramid prepare %.3f, match %.3f, pyramid total %.3f, " + ...
    "display %.3f, total %.3f\n", ...
    report.Timing.ReadAndCropSeconds, report.Timing.WarpSeconds, ...
    report.Timing.PrepareSeconds, report.Timing.MatchSeconds, ...
    report.Timing.PyramidSeconds, report.Timing.DisplaySeconds, ...
    report.Timing.TotalSeconds);
for level = report.LevelReports.'
    fprintf("    factor %d: %d x %d, %d tiles, candidates %d/%g/%d " + ...
        "(min/median/max), %.3f s prepare, %.3f s match\n", ...
        level.Factor, level.ImageSize(1), level.ImageSize(2), ...
        level.TileCount, level.CandidateCountMinimum, ...
        level.CandidateCountMedian, level.CandidateCountMaximum, ...
        level.PrepareSeconds, level.MatchSeconds);
end
if ~isempty(report.ThreadTuning)
    fprintf("  Thread tuning (recommended %d):\n", ...
        report.ThreadTuning.RecommendedWorkers);
    disp(report.ThreadTuning.Results);
end
fprintf("  Result: valid %.1f%%, median cost %.4f, " + ...
    "median margin %.4f, median displacement [%.1f, %.1f] pixels\n", ...
    100 * report.Summary.ValidFraction, report.Summary.MedianCost, ...
    report.Summary.MedianMargin, ...
    report.Summary.MedianDisplacementX, ...
    report.Summary.MedianDisplacementY);
if report.Summary.TruthSampleCount > 0
    fprintf("  Residual X (estimated - expected): median %.3f, " + ...
        "median absolute %.3f, RMSE %.3f pixels\n", ...
        report.Summary.MedianResidualX, ...
        report.Summary.MedianAbsoluteResidualX, ...
        report.Summary.RmseResidualX);
    fprintf("  Residual Y (estimated - expected): median %.3f, " + ...
        "median absolute %.3f, RMSE %.3f pixels\n", ...
        report.Summary.MedianResidualY, ...
        report.Summary.MedianAbsoluteResidualY, ...
        report.Summary.RmseResidualY);
    fprintf("  Known-correspondence median endpoint error: %.3f pixels (%d samples)\n", ...
        report.Summary.MedianEndpointError, ...
        report.Summary.TruthSampleCount);
end
end
